 ('85852597-ea64-57e0-bb2b-4bb401b19f00','20000000-0000-0000-0000-000000000003','C1',25,$p$Precisión y matiz léxico: el mot juste$p$,'#6C3483','auto_stories')
insert into lessons (id, unit_id, order_index, title, description, type, xp_reward) values
 ('a737257b-c2fe-5175-bb01-d9798e395a2c','85852597-ea64-57e0-bb2b-4bb401b19f00',1,$p$Sinónimos finos y sus matices (habitation, regarder, aimer…)$p$,$p$Sinónimos finos y sus matices (habitation, regarder, aimer…)$p$,'lesson',15),
 ('66c066b6-079b-5c0f-9f4c-a83ee41edf41','85852597-ea64-57e0-bb2b-4bb401b19f00',2,$p$Colocaciones verbo + sustantivo (prendre une décision, tirer une conclusion)$p$,$p$Colocaciones verbo + sustantivo (prendre une décision, tirer une conclusion)$p$,'lesson',15),
 ('2cb6ac69-5857-55ab-846e-0b495fddfafa','85852597-ea64-57e0-bb2b-4bb401b19f00',3,$p$Registros: soutenu, courant, familier$p$,$p$Registros: soutenu, courant, familier$p$,'lesson',15),
 ('d4ed0443-1542-528a-b42a-a37e6c5d0e47','85852597-ea64-57e0-bb2b-4bb401b19f00',4,$p$Precisión: davantage/plus, an/année, jour/journée y expresiones fijas$p$,$p$Precisión: davantage/plus, an/année, jour/journée y expresiones fijas$p$,'lesson',15),
 ('2955e138-6ef4-5ea1-8c73-251719807e31','85852597-ea64-57e0-bb2b-4bb401b19f00',5,$p$🏁 Checkpoint Unité 25$p$,$p$Demuestra que eliges el mot juste a nivel C1: distingues sinónimos finos y sus connotaciones (habitation/logement/domicile/foyer, regarder/observer/scruter/contempler, adorer/apprécier/aimer), dominas las colocaciones verbo+sustantivo (prendre une décision, tirer une conclusion, nourrir un espoir), adaptas el registro (soutenu/courant/familier: automobile/voiture/bagnole) y evitas errores de precisión (davantage vs plus, an vs année, jour vs journée).$p$,'checkpoint',40)
