('95419f73-c50f-5b99-8aff-b995b887b4de'::uuid,'20000000-0000-0000-0000-000000000003'::uuid,'C1','reading','multiple_choice',$p$Elige el verbo que expresa observar con atención minuciosa, casi con inquietud: «Le détective ___ chaque détail de la photographie.»$p$,$j${"options": ["scrutait", "apercevait", "entrevoyait"]}$j$::jsonb,$j${"value": "scrutait"}$j$::jsonb,0.84,ARRAY[$p$unidad25$p$, $p$synonymes_regarder_scruter$p$, $p$reading$p$]),
('89d4f02c-5375-592d-8633-bc874dd55b14'::uuid,'20000000-0000-0000-0000-000000000003'::uuid,'C1','writing','cloze',$p$Completa con el verbo que expresa mirar algo bello con admiración serena (infinitivo, tras «pour»): «Ils se sont arrêtés pour ___ le coucher de soleil.»$p$,$j${"text": "Ils se sont arrêtés pour ___ le coucher de soleil."}$j$::jsonb,$j${"value": "contempler", "accepted": ["contempler"]}$j$::jsonb,0.84,ARRAY[$p$unidad25$p$, $p$synonymes_contempler_cloze$p$, $p$writing$p$]),
