('809ffb13-5638-5653-a57a-f892a40b206e'::uuid,'20000000-0000-0000-0000-000000000003'::uuid,'C1','reading','match',$p$Relaciona cada verbo con el sustantivo con el que forma la colocación fija correcta.$p$,$j${"pairs": [{"en": "prendre", "es": "une décision"}, {"en": "tirer", "es": "une conclusion"}, {"en": "nourrir", "es": "un espoir"}]}$j$::jsonb,$j${"pairs": [["prendre", "une décision"], ["tirer", "une conclusion"], ["nourrir", "un espoir"]]}$j$::jsonb,0.84,ARRAY[$p$unidad25$p$, $p$collocations_match$p$, $p$reading$p$]),
('08e6ee59-966a-592d-845c-6fc254157260'::uuid,'20000000-0000-0000-0000-000000000003'::uuid,'C1','reading','multiple_choice',$p$Elige el verbo que forma la colocación correcta con «une décision» en francés (no se calca del español «tomar»): «Le conseil doit ___ une décision avant vendredi.»$p$,$j${"options": ["prendre", "faire", "donner"]}$j$::jsonb,$j${"value": "prendre"}$j$::jsonb,0.84,ARRAY[$p$unidad25$p$, $p$collocations_prendre_decision$p$, $p$reading$p$]),
('6f77b51c-8489-5bb0-a400-30a3fa7765f7'::uuid,'20000000-0000-0000-0000-000000000003'::uuid,'C1','writing','translation',$p$Traduce usando la colocación culta «formuler une hypothèse»: «El investigador formuló una hipótesis audaz.»$p$,$j${"source": "El investigador formuló una hipótesis audaz."}$j$::jsonb,$j${"value": "Le chercheur a formulé une hypothèse audacieuse.", "accepted": ["Le chercheur a formulé une hypothèse audacieuse", "Le chercheur a formulé une hypothèse audacieuse.", "le chercheur a formulé une hypothèse audacieuse"]}$j$::jsonb,0.84,ARRAY[$p$unidad25$p$, $p$collocations_formuler_hypothese_translation$p$, $p$writing$p$]),
