insert into lessons (id, unit_id, order_index, title, description, type, xp_reward) values
 ('3e90da00-81e7-52b4-b401-f012d66680a6','b9c764c9-3c54-5875-a47b-8fbf3cdd9cf9',1,$p$Mise en relief: c'est… que, ce dont… c'est, ce à quoi$p$,$p$Mise en relief: c'est… que, ce dont… c'est, ce à quoi$p$,'lesson',15),
 ('3858afed-7245-5d3a-981f-809ce8329e81','b9c764c9-3c54-5875-a47b-8fbf3cdd9cf9',2,$p$Dislocation: Moi, je…; Ce livre, je l'ai adoré$p$,$p$Dislocation: Moi, je…; Ce livre, je l'ai adoré$p$,'lesson',15),
 ('a300e0f4-a62b-5596-b272-b16b32af4b76','b9c764c9-3c54-5875-a47b-8fbf3cdd9cf9',3,$p$Inversion stylistique: peut-être, à peine… que, ainsi$p$,$p$Inversion stylistique: peut-être, à peine… que, ainsi$p$,'lesson',15),
 ('86f24166-157d-5c07-8c2c-392c99b204b4','b9c764c9-3c54-5875-a47b-8fbf3cdd9cf9',4,$p$Litote, euphémisme y négation soutenue$p$,$p$Litote, euphémisme y négation soutenue$p$,'lesson',15),
 ('6163c5f4-557a-541d-ac4b-859ff22cb50f','b9c764c9-3c54-5875-a47b-8fbf3cdd9cf9',5,$p$🏁 Checkpoint Unité 27$p$,$p$Demuestra que dominas la mise en relief avanzada (c'est… que/qui, ce qui/ce que/ce dont… c'est, ce à quoi, si… c'est que), la dislocation (Moi, je…; Ce livre, je l'ai adoré), la inversion stylistique (Peut-être a-t-il raison; À peine était-il arrivé que…; Ainsi va la vie), la négation soutenue (ne… guère, ne… point, ne… nullement) y la inferencia/sobreentendido (litote «ce n'est pas mauvais», eufemismo, presupuesto).$p$,'checkpoint',40)
