insert into units (id, course_id, cefr_level, order_index, title, theme_color, icon) values
 ('0df10914-30f4-5ce9-ad5a-e2c96d582b23','20000000-0000-0000-0000-000000000003','C1',29,$p$Hipótesis y modalidad avanzada$p$,'#8E44AD','psychology_alt')
insert into lessons (id, unit_id, order_index, title, description, type, xp_reward) values
 ('d7863dea-f1a7-57d8-b13d-d069c60c0013','0df10914-30f4-5ce9-ad5a-e2c96d582b23',1,$p$Subordinadas hipotéticas cultas (à supposer que, pour peu que, à moins que… ne)$p$,$p$Subordinadas hipotéticas cultas (à supposer que, pour peu que, à moins que… ne)$p$,'lesson',15),
 ('a9039879-7617-5332-961e-d86ddc5a35a2','0df10914-30f4-5ce9-ad5a-e2c96d582b23',2,$p$Au cas où + condicional · quitte à · condicional periodístico$p$,$p$Au cas où + condicional · quitte à · condicional periodístico$p$,'lesson',15),
 ('3ea65f64-646a-5b27-b0a3-f973d2e543ad','0df10914-30f4-5ce9-ad5a-e2c96d582b23',3,$p$Modalidad matizada: il se peut que, il n'est pas exclu que, force est de reconnaître$p$,$p$Modalidad matizada: il se peut que, il n'est pas exclu que, force est de reconnaître$p$,'lesson',15),
 ('601946e4-aa7f-5d24-9bd7-7f2f21b1b9ba','0df10914-30f4-5ce9-ad5a-e2c96d582b23',4,$p$Subjuntivo soutenu tras le seul / le premier / il n'y a que… qui$p$,$p$Subjuntivo soutenu tras le seul / le premier / il n'y a que… qui$p$,'lesson',15),
 ('975dbc2b-3872-5664-87a6-bcac16c0819e','0df10914-30f4-5ce9-ad5a-e2c96d582b23',5,$p$🏁 Checkpoint Unité 29$p$,$p$Demuestra que manejas la hipótesis y la modalidad a nivel C1: encadenas subordinadas hipotéticas cultas (à supposer que + subj, pour peu que + subj, à moins que… ne + subj, en admettant que + subj), usas «au cas où» + condicional y «quitte à» + infinitivo, reconoces el condicional periodístico de la información no confirmada (Le président aurait déclaré…), matizas la modalidad entre probabilidad y obligación (il se peut que, il n'est pas exclu que, force est de reconnaître) y aplicas el subjuntivo del registro soutenu tras «le seul/le premier/il n'y a que… qui».$p$,'checkpoint',40)
