('0f92bde5-ca0c-5b3d-a0ea-a7a3db9bed8b'::uuid,'20000000-0000-0000-0000-000000000003'::uuid,'C1','writing','cloze',$p$«Il n'est pas exclu que» rige subjuntivo. Completa con el subjuntivo presente de «avoir» (3ª pers. sing.): «Il n'est pas exclu qu'il ___ raison sur ce point.»$p$,$j${"text": "Il n'est pas exclu qu'il ___ raison sur ce point."}$j$::jsonb,$j${"value": "ait", "accepted": ["ait"]}$j$::jsonb,0.84,ARRAY[$p$unidad29$p$, $p$modalite_il_nest_pas_exclu_que_cloze$p$, $p$writing$p$]),
('696ecbdb-e39a-5c7c-bdfc-c8498e484c98'::uuid,'20000000-0000-0000-0000-000000000003'::uuid,'C1','writing','translation',$p$Traduce con la fórmula soutenue «force est de reconnaître que» (hay que reconocer que): «Hay que reconocer que el resultado nos sorprendió.»$p$,$j${"source": "Hay que reconocer que el resultado nos sorprendió."}$j$::jsonb,$j${"value": "Force est de reconnaître que le résultat nous a surpris.", "accepted": ["Force est de reconnaître que le résultat nous a surpris", "Force est de reconnaître que le résultat nous a surpris.", "force est de reconnaître que le résultat nous a surpris"]}$j$::jsonb,0.84,ARRAY[$p$unidad29$p$, $p$modalite_force_est_de_reconnaitre_translation$p$, $p$writing$p$]),
